import{_ as e,o as d,c as o,ag as a}from"./chunks/framework.BYYsWsaA.js";const r="/docs/images/formula-examples.png",b=JSON.parse('{"title":"Formulas","description":"","frontmatter":{},"headers":[],"relativePath":"guide/formulas.md","filePath":"guide/formulas.md"}'),c={name:"guide/formulas.md"};function l(s,t,n,h,i,u){return d(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="formulas" tabindex="-1">Formulas <a class="header-anchor" href="#formulas" aria-label="Permalink to &quot;Formulas&quot;">​</a></h1><p>Wafflebase supports <strong>430+ functions</strong> — the same ones you know from Google Sheets. This page covers the essentials. For a hands-on tutorial, see <a href="./build-a-budget.html">Build a Budget Spreadsheet</a>.</p><h2 id="how-formulas-work" tabindex="-1">How Formulas Work <a class="header-anchor" href="#how-formulas-work" aria-label="Permalink to &quot;How Formulas Work&quot;">​</a></h2><p>Type <code>=</code> in any cell to start a formula:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=SUM(A1:A10)</span></span></code></pre></div><p>A formula can reference other cells, use operators, and call functions. The result is calculated automatically and updates whenever the referenced cells change.</p><p><img src="'+r+'" alt="Formula calculation examples"></p><h3 id="cell-references" tabindex="-1">Cell References <a class="header-anchor" href="#cell-references" aria-label="Permalink to &quot;Cell References&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Example</th><th>Meaning</th></tr></thead><tbody><tr><td>Single cell</td><td><code>A1</code></td><td>The value in column A, row 1</td></tr><tr><td>Range</td><td><code>A1:C10</code></td><td>All cells from A1 to C10</td></tr><tr><td>Cross-sheet</td><td><code>Sheet2!A1</code></td><td>Cell A1 in another tab</td></tr></tbody></table><h3 id="operators" tabindex="-1">Operators <a class="header-anchor" href="#operators" aria-label="Permalink to &quot;Operators&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Example</th><th>Result</th></tr></thead><tbody><tr><td><code>+</code> <code>-</code> <code>*</code> <code>/</code></td><td><code>=A1 * 1.1</code></td><td>Arithmetic</td></tr><tr><td><code>&gt;</code> <code>&lt;</code> <code>=</code> <code>&lt;&gt;</code></td><td><code>=A1 &gt; 100</code></td><td>TRUE or FALSE</td></tr><tr><td><code>&amp;</code></td><td><code>=A1 &amp; &quot; &quot; &amp; B1</code></td><td>Joins text</td></tr></tbody></table><h2 id="most-used-functions" tabindex="-1">Most Used Functions <a class="header-anchor" href="#most-used-functions" aria-label="Permalink to &quot;Most Used Functions&quot;">​</a></h2><h3 id="totals-and-averages" tabindex="-1">Totals and Averages <a class="header-anchor" href="#totals-and-averages" aria-label="Permalink to &quot;Totals and Averages&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>What It Does</th><th>Example</th></tr></thead><tbody><tr><td><code>SUM</code></td><td>Add up values</td><td><code>=SUM(B2:B10)</code></td></tr><tr><td><code>AVERAGE</code></td><td>Mean of values</td><td><code>=AVERAGE(B2:B10)</code></td></tr><tr><td><code>COUNT</code></td><td>Count numbers</td><td><code>=COUNT(B2:B10)</code></td></tr><tr><td><code>COUNTA</code></td><td>Count non-empty cells</td><td><code>=COUNTA(A:A)</code></td></tr><tr><td><code>MIN</code> / <code>MAX</code></td><td>Smallest / largest</td><td><code>=MAX(B2:B10)</code></td></tr></tbody></table><h3 id="conditional" tabindex="-1">Conditional <a class="header-anchor" href="#conditional" aria-label="Permalink to &quot;Conditional&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>What It Does</th><th>Example</th></tr></thead><tbody><tr><td><code>IF</code></td><td>Choose between two values</td><td><code>=IF(A1&gt;0, &quot;Profit&quot;, &quot;Loss&quot;)</code></td></tr><tr><td><code>IFERROR</code></td><td>Fallback if formula errors</td><td><code>=IFERROR(A1/B1, 0)</code></td></tr><tr><td><code>SUMIF</code></td><td>Sum where condition matches</td><td><code>=SUMIF(A:A, &quot;Sales&quot;, B:B)</code></td></tr><tr><td><code>COUNTIF</code></td><td>Count where condition matches</td><td><code>=COUNTIF(A:A, &quot;&gt;100&quot;)</code></td></tr><tr><td><code>IFS</code></td><td>Multiple conditions</td><td><code>=IFS(A1&gt;=90,&quot;A&quot;, A1&gt;=80,&quot;B&quot;, TRUE,&quot;C&quot;)</code></td></tr></tbody></table><h3 id="text" tabindex="-1">Text <a class="header-anchor" href="#text" aria-label="Permalink to &quot;Text&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>What It Does</th><th>Example</th></tr></thead><tbody><tr><td><code>CONCATENATE</code></td><td>Join strings</td><td><code>=CONCATENATE(A1, &quot; &quot;, B1)</code></td></tr><tr><td><code>LEFT</code> / <code>RIGHT</code></td><td>Extract characters</td><td><code>=LEFT(A1, 3)</code></td></tr><tr><td><code>TRIM</code></td><td>Remove extra spaces</td><td><code>=TRIM(A1)</code></td></tr><tr><td><code>UPPER</code> / <code>LOWER</code></td><td>Change case</td><td><code>=UPPER(A1)</code></td></tr><tr><td><code>SUBSTITUTE</code></td><td>Replace text</td><td><code>=SUBSTITUTE(A1, &quot;old&quot;, &quot;new&quot;)</code></td></tr></tbody></table><h3 id="lookup" tabindex="-1">Lookup <a class="header-anchor" href="#lookup" aria-label="Permalink to &quot;Lookup&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>What It Does</th><th>Example</th></tr></thead><tbody><tr><td><code>VLOOKUP</code></td><td>Find a value in a table</td><td><code>=VLOOKUP(&quot;Alice&quot;, A:C, 3, FALSE)</code></td></tr><tr><td><code>XLOOKUP</code></td><td>Flexible lookup (recommended)</td><td><code>=XLOOKUP(A1, D:D, E:E)</code></td></tr><tr><td><code>INDEX</code> + <code>MATCH</code></td><td>Look up by position</td><td><code>=INDEX(B:B, MATCH(&quot;Alice&quot;, A:A, 0))</code></td></tr></tbody></table><h3 id="date" tabindex="-1">Date <a class="header-anchor" href="#date" aria-label="Permalink to &quot;Date&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>What It Does</th><th>Example</th></tr></thead><tbody><tr><td><code>TODAY</code></td><td>Current date</td><td><code>=TODAY()</code></td></tr><tr><td><code>DAYS</code></td><td>Days between two dates</td><td><code>=DAYS(B1, A1)</code></td></tr><tr><td><code>YEAR</code> / <code>MONTH</code> / <code>DAY</code></td><td>Extract date parts</td><td><code>=YEAR(A1)</code></td></tr><tr><td><code>EDATE</code></td><td>Add months to a date</td><td><code>=EDATE(A1, 3)</code></td></tr></tbody></table><h2 id="all-supported-categories" tabindex="-1">All Supported Categories <a class="header-anchor" href="#all-supported-categories" aria-label="Permalink to &quot;All Supported Categories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Functions</th></tr></thead><tbody><tr><td>Statistical</td><td>116</td></tr><tr><td>Math</td><td>84</td></tr><tr><td>Engineering</td><td>50</td></tr><tr><td>Financial</td><td>49</td></tr><tr><td>Text</td><td>38</td></tr><tr><td>Lookup</td><td>32</td></tr><tr><td>Date &amp; Time</td><td>25</td></tr><tr><td>Info</td><td>21</td></tr><tr><td>Database</td><td>12</td></tr><tr><td>Logical</td><td>10</td></tr></tbody></table><p>Wafflebase covers ~85% of Google Sheets functions. Most common functions are fully supported.</p>',25)])])}const m=e(c,[["render",l]]);export{b as __pageData,m as default};
